    20→      --cor-rosa-claro: #f5ede4;
    21→      --fonte-titulo: 'Cormorant Garamond', serif;
    22→      --fonte-corpo: 'Jost', sans-serif;
    23→    }
    24→
    25→    /* ============================================
    26→       RESET & BASE
    27→    ============================================ */
    28→    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    29→    html { scroll-behavior: smooth; }
    30→    body {
    31→      font-family: var(--fonte-corpo);
    32→      color: var(--cor-texto);
    33→      background: var(--cor-fundo);
    34→      font-size: 16px;
    35→      line-height: 1.7;
    36→    }
