.proc-card-body { padding: 24px 20px; }
.proc-card-body h3 {
  font-family: var(--fonte-titulo);
  font-size: 1.2rem;
  font-weight: 400;
  line-height: 1.3;
  margin-bottom: 8px;
}
.proc-card-body p {
  font-size: 13px;
  font-weight: 300;
  color: var(--cor-texto-claro);
  margin-bottom: 16px;
  line-height: 1.6;
}
.proc-card-link {
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: var(--cor-primaria);
  display: flex;
  align-items: center;
  gap: 8px;
  transition: gap 0.2s;
}
.proc-card-link:hover { gap: 14px; }
.proc-card-link::after { content: '→'; }

/* Tabs de procedimentos */
.proc-tabs {
  display: flex;
  gap: 4px;
  margin-bottom: 40px;
  flex-wrap: wrap;
}
.proc-tab {
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 2px;
  text-transform: uppercase;
  padding: 10px 24px;
  border: 1px solid rgba(201,169,122,0.3);
  color: var(--cor-texto-claro);
  cursor: pointer;
  transition: all 0.2s;
  background: transparent;
  font-family: var(--fonte-corpo);
}
.proc-tab.active, .proc-tab:hover {
  background: var(--cor-primaria);
  color: var(--cor-branco);
  border-color: var(--cor-primaria);
}
.proc-panel { display: none; }
.proc-panel.active { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 24px; }

/* ============================================
   SOBRE A CLÍNICA
============================================ */
.sobre {
  padding: 100px 0;
  background: var(--cor-fundo-secao);
}
.sobre-inner {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 80px;
  align-items: center;
}
.sobre-image { position: relative; }
.sobre-img-frame {
  width: 100%;
  aspect-ratio: 3/4;
  background: linear-gradient(160deg, #e0cbb5 0%, #c9a97a 100%);
  border-radius: 60px 2px 60px 2px;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  color: rgba(255,255,255,0.5);
  font-family: var(--fonte-titulo);
  font-style: italic;
}
.sobre-deco {
  position: absolute;
  bottom: -20px; right: -20px;
  width: 200px; height: 200px;
  border: 1px solid rgba(201,169,122,0.3);
  border-radius: 50%;
  z-index: -1;
}
.sobre-deco-2 {
  position: absolute;
  top: -15px; left: -15px;
  width: 80px; height: 80px;
  background: var(--cor-rosa-claro);
  border-radius: 50%;
  z-index: -1;
}
.sobre-content { padding: 20px 0; }
.sobre-content p {
  font-size: 15px;
  font-weight: 300;
  color: var(--cor-texto-claro);
  line-height: 1.9;
  margin-bottom: 20px;
}
.sobre-content strong { color: var(--cor-texto); font-weight: 500; }

/* Pilares */
.pilares {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
  margin: 36px 0;
}
.pilar {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 16px;
  background: var(--cor-branco);
  border: 1px solid rgba(201,169,122,0.15);
}
.pilar-icon {
  width: 40px;
  height: 40px;
  background: var(--cor-rosa-claro);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  font-size: 18px;
}
.pilar-text {
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.5px;
  color: var(--cor-texto);
}

