============================================ */
.depoimentos {
  padding: 100px 0;
  background: var(--cor-fundo);
  overflow: hidden;
}
.depoimentos-header { text-align: center; margin-bottom: 60px; }
.depoimentos-header .divider { margin: 20px auto; }
.depoimentos-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 20px;
}
.dep-card {
  position: relative;
  overflow: hidden;
  border-radius: 2px;
  cursor: pointer;
}
.dep-card-img {
  aspect-ratio: 4/5;
  background: linear-gradient(145deg, #e8d5c0, #d4b896);
  overflow: hidden;
  position: relative;
}
.dep-card-img img { width: 100%; height: 100%; object-fit: cover; transition: transform 0.5s; }
.dep-card:hover .dep-card-img img { transform: scale(1.05); }
.dep-card-overlay {
  position: absolute;
  bottom: 0; left: 0; right: 0;
  background: linear-gradient(to top, rgba(0,0,0,0.6) 0%, transparent 100%);
  padding: 30px 16px 16px;
  opacity: 0;
  transition: opacity 0.3s;
}
.dep-card:hover .dep-card-overlay { opacity: 1; }
.dep-card-handle {
  color: var(--cor-branco);
  font-size: 13px;
  font-weight: 400;
}
.dep-card-label {
  position: absolute;
  bottom: 12px;
  left: 12px;
  background: rgba(255,255,255,0.9);
  padding: 6px 12px;
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 1px;
