  width: 100%;
  aspect-ratio: 4/3;
  background: #ede4d8;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--fonte-titulo);
  font-style: italic;
  color: rgba(120,80,40,0.4);
